onTextChanged:
{{(() => {
     // Clear existing timeout
     clearInterval(appsmith.store.newPickupGeoTimeout);

     if (NewPickupAddressInput.text && NewPickupAddressInput.text.length > 2) {
       // Create new timeout
       const timeoutId = setInterval(() => {
         GeocodeNewPickupAddress.run().then(() => {
           if (GeocodeNewPickupAddress.data?.length > 0) {
             LocationManager.updateNewPickupFromGeocode();
           }
         });
         // Clear after running once
         clearInterval(appsmith.store.newPickupGeoTimeout);
       }, 1500);

       // Store timeout ID
       storeValue('newPickupGeoTimeout', timeoutId);
     }
   })()}}
